def wordBreak(s, wordDict):
    words = set(wordDict)
    memo = {}
    def bt(start):
        if start in memo: return memo[start]
        if start == len(s): return ['']
        res = []
        for end in range(start+1, len(s)+1):
            word = s[start:end]
            if word in words:
                for sent in bt(end):
                    res.append(word + (' ' + sent if sent else ''))
        memo[start] = res
        return res
    return bt(0)

